// src/components/Projects.js
import React, { useRef, useState, useCallback, useEffect } from 'react';
import { PROJECTS } from '../data/projects';
import './Projects.css';

/**
 * Projects — horizontal scroll carousel.
 * 
 * Interaction model:
 *  - Native CSS scroll-snap on a scrollable track (works on touch/mobile natively)
 *  - Pointer drag for desktop (mousedown → mousemove → mouseup)
 *  - Arrow buttons
 *  - Dot indicators
 * 
 * The infinite loop is achieved by prepending/appending clone cards and
 * silently repositioning when the user reaches the clones.
 */
export default function Projects() {
  const trackRef = useRef(null);
  const [activeIndex, setActiveIndex] = useState(0);
  const [videoModal, setVideoModal] = useState(null); // project object | null
  const isDragging = useRef(false);
  const dragStartX = useRef(0);
  const scrollStartLeft = useRef(0);
  const hasDragged = useRef(false);

  const total = PROJECTS.length;
  // We prepend 2 clones at start and append 2 clones at end for the loop
  const CLONE_COUNT = 2;
  const allCards = [
    ...PROJECTS.slice(-CLONE_COUNT),
    ...PROJECTS,
    ...PROJECTS.slice(0, CLONE_COUNT),
  ];

  // On mount: scroll to the first real card (after the leading clones)
  useEffect(() => {
    const track = trackRef.current;
    if (!track) return;
    const cardW = track.scrollWidth / allCards.length;
    track.scrollLeft = cardW * CLONE_COUNT;
    // disable smooth scroll for initial position
  }, []);

  // Keep activeIndex in sync with scroll position
  const updateActiveIndex = useCallback(() => {
    const track = trackRef.current;
    if (!track) return;
    const cardW = track.scrollWidth / allCards.length;
    const rawIndex = Math.round(track.scrollLeft / cardW);
    // map clone indices back to real indices
    const realIndex = ((rawIndex - CLONE_COUNT) % total + total) % total;
    setActiveIndex(realIndex);
  }, [allCards.length, total]);

  // Seamless loop: after scrolling to a clone, silently jump to the real card
  const handleScrollEnd = useCallback(() => {
    const track = trackRef.current;
    if (!track) return;
    const cardW = track.scrollWidth / allCards.length;
    const rawIndex = Math.round(track.scrollLeft / cardW);

    if (rawIndex < CLONE_COUNT) {
      // Jumped to leading clone — jump to matching real card at the end
      const target = rawIndex + total;
      track.scrollLeft = cardW * target;
    } else if (rawIndex >= CLONE_COUNT + total) {
      // Jumped to trailing clone — jump to matching real card at the start
      const target = rawIndex - total;
      track.scrollLeft = cardW * target;
    }
    updateActiveIndex();
  }, [allCards.length, total, updateActiveIndex]);

  useEffect(() => {
    const track = trackRef.current;
    if (!track) return;
    track.addEventListener('scroll', updateActiveIndex, { passive: true });
    track.addEventListener('scrollend', handleScrollEnd, { passive: true });
    // Fallback for browsers without scrollend
    let timer;
    const onScroll = () => {
      clearTimeout(timer);
      timer = setTimeout(handleScrollEnd, 120);
    };
    track.addEventListener('scroll', onScroll, { passive: true });
    return () => {
      track.removeEventListener('scroll', updateActiveIndex);
      track.removeEventListener('scrollend', handleScrollEnd);
      track.removeEventListener('scroll', onScroll);
      clearTimeout(timer);
    };
  }, [handleScrollEnd, updateActiveIndex]);

  // ── Pointer drag (desktop) ──
  const onPointerDown = (e) => {
    if (e.button !== 0) return; // left click only
    isDragging.current = true;
    hasDragged.current = false;
    dragStartX.current = e.clientX;
    scrollStartLeft.current = trackRef.current.scrollLeft;
    trackRef.current.style.cursor = 'grabbing';
    trackRef.current.style.userSelect = 'none';
    e.currentTarget.setPointerCapture(e.pointerId);
  };

  const onPointerMove = (e) => {
    if (!isDragging.current) return;
    const dx = e.clientX - dragStartX.current;
    if (Math.abs(dx) > 4) hasDragged.current = true;
    trackRef.current.scrollLeft = scrollStartLeft.current - dx;
  };

  const onPointerUp = (e) => {
    if (!isDragging.current) return;
    isDragging.current = false;
    trackRef.current.style.cursor = 'grab';
    trackRef.current.style.userSelect = '';
    e.currentTarget.releasePointerCapture(e.pointerId);
    // Snap to nearest card
    const track = trackRef.current;
    const cardW = track.scrollWidth / allCards.length;
    const nearest = Math.round(track.scrollLeft / cardW);
    track.scrollTo({ left: nearest * cardW, behavior: 'smooth' });
  };

  // ── Arrow nav ──
  const scrollToReal = (realIndex) => {
    const track = trackRef.current;
    if (!track) return;
    const cardW = track.scrollWidth / allCards.length;
    const clampedReal = ((realIndex % total) + total) % total;
    const target = clampedReal + CLONE_COUNT;
    track.scrollTo({ left: cardW * target, behavior: 'smooth' });
  };

  const handlePrev = () => scrollToReal(activeIndex - 1);
  const handleNext = () => scrollToReal(activeIndex + 1);

  return (
    <section id="projects" className="projects">
      <div className="projects__header">
        <div className="section-label">Projects</div>
        <h2 className="section-title">Things I've <em>built</em></h2>
        <p className="projects__hint">
          Drag, swipe, or use arrows — loops continuously
        </p>
      </div>

      {/* Scrollable track */}
      <div
        className="projects__track"
        ref={trackRef}
        onPointerDown={onPointerDown}
        onPointerMove={onPointerMove}
        onPointerUp={onPointerUp}
        onPointerLeave={onPointerUp}
        style={{ cursor: 'grab' }}
      >
        {allCards.map((project, i) => (
          <ProjectCard
            key={`${project.id}-${i}`}
            project={project}
            onDemoClick={() => !hasDragged.current && setVideoModal(project)}
          />
        ))}
      </div>

      {/* Controls */}
      <div className="projects__controls">
        <button className="ctrl-btn" onClick={handlePrev} aria-label="Previous">
          <ChevronLeft />
        </button>
        <div className="ctrl-dots">
          {PROJECTS.map((_, i) => (
            <button
              key={i}
              className={`dot${i === activeIndex ? ' dot--active' : ''}`}
              onClick={() => scrollToReal(i)}
              aria-label={`Go to project ${i + 1}`}
            />
          ))}
        </div>
        <button className="ctrl-btn" onClick={handleNext} aria-label="Next">
          <ChevronRight />
        </button>
      </div>

      <p className="projects__counter">
        {String(activeIndex + 1).padStart(2, '0')} / {String(total).padStart(2, '0')}
      </p>

      {videoModal && (
        <VideoModal project={videoModal} onClose={() => setVideoModal(null)} />
      )}
    </section>
  );
}

/* ── Project Card ── */
function ProjectCard({ project, onDemoClick }) {
  return (
    <article className="project-card" style={{ '--card-accent': project.accentColor, '--card-bg': project.color }}>
      <div className="pc__top-bar" />
      <div className="pc__body">
        <div className="pc__meta">
          <span className="pc__year">{project.year}</span>
          <span className="pc__status" data-ongoing={project.status === 'Ongoing'}>
            {project.status}
          </span>
        </div>
        <h3 className="pc__title">{project.title}</h3>
        <p className="pc__subtitle">{project.subtitle}</p>
        <p className="pc__desc">{project.description}</p>
        <div className="pc__tech">
          {project.tech.map(t => <span key={t} className="pc__tag">{t}</span>)}
        </div>
        <div className="pc__actions">
          <button className="pc__demo-btn" onClick={onDemoClick}>
            <PlayIcon /> Watch Demo
          </button>
          <a
            href={project.githubUrl}
            target="_blank"
            rel="noreferrer"
            className="pc__github-btn"
            onClick={e => e.stopPropagation()}
          >
            <GithubIcon /> GitHub
          </a>
        </div>
      </div>
    </article>
  );
}

/* ── Video Modal ── */
function VideoModal({ project, onClose }) {
  const getYtId = (u) => { const m = u.match(/(?:v=|youtu\.be\/)([^&?/]+)/); return m?.[1]; };
  const ytId = getYtId(project.demoUrl);

  useEffect(() => {
    const onKey = (e) => { if (e.key === 'Escape') onClose(); };
    window.addEventListener('keydown', onKey);
    return () => window.removeEventListener('keydown', onKey);
  }, [onClose]);

  return (
    <div className="video-modal" onClick={onClose}>
      <div className="video-modal__box" onClick={e => e.stopPropagation()}>
        <button className="video-modal__close" onClick={onClose}>✕</button>
        <div className="video-modal__title">{project.title}</div>
        <div className="video-modal__embed">
          {ytId
            ? <iframe src={`https://www.youtube.com/embed/${ytId}?autoplay=1`}
                allow="autoplay; encrypted-media" allowFullScreen title="Demo" />
            : <div className="video-modal__placeholder">Demo video coming soon</div>
          }
        </div>
      </div>
    </div>
  );
}

